     5→//! Steeplechase Operations - git history parsing for JJ session tracking
     6→//!
     7→//! Implements jjx_rein: parse git history for steeplechase entries belonging to a Heat.
     8→//! Steeplechase entries are stored in git commit messages, not the Gallops JSON.
     9→//!
    10→//! Commit format: `jjb:HALLMARK:IDENTITY:ACTION: message`
    11→//! - HALLMARK: Version identifier (NNNN or NNNN-xxxxxxx)
    12→//! - IDENTITY: ₢CORONET for pace-level, ₣FIREMARK for heat-level
    13→//! - ACTION: Single letter code (required for all commits)
    14→
    15→use serde::Serialize;
    16→use std::process::Command;
    17→
    18→use crate::jjrf_favor::{jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX, JJRF_CORONET_PREFIX as CORONET_PREFIX};
    19→
    20→/// Arguments for jjx_rein command
    21→#[derive(Debug)]
    22→pub struct jjrs_ReinArgs {
    23→    /// Target Heat identity (Firemark, with or without prefix)
    24→    pub firemark: String,
    25→
    26→    /// Maximum entries to return
    27→    pub limit: usize,
    28→}
    29→
    30→/// Steeplechase entry - parsed from git commit message
    31→#[derive(Debug, Clone, Serialize, Default)]
    32→pub struct jjrs_SteeplechaseEntry {
    33→    /// Timestamp in "YYYY-MM-DD HH:MM" format
    34→    pub timestamp: String,
    35→
    36→    /// Abbreviated git commit SHA
    37→    pub commit: String,
    38→
    39→    /// Hallmark version identifier (NNNN or NNNN-xxxxxxx)
    40→    #[serde(skip_serializing_if = "Option::is_none")]
    41→    pub hallmark: Option<String>,
    42→
    43→    /// Coronet for pace-level entries, None for heat-level
    44→    #[serde(skip_serializing_if = "Option::is_none")]
    45→    pub coronet: Option<String>,
    46→
    47→    /// Action code (single letter), 'n' for standard notch commits
    48→    #[serde(skip_serializing_if = "Option::is_none")]
    49→    pub action: Option<String>,
    50→
    51→    /// Commit message or marker description
    52→    pub subject: String,
    53→}
    54→
    55→/// Parse timestamp from git %ai format to "YYYY-MM-DD HH:MM"
    56→/// Input format: "2024-01-15 14:30:00 -0800"
    57→pub(crate) fn zjjrs_parse_timestamp(git_timestamp: &str) -> String {
    58→    let trimmed = git_timestamp.trim();
    59→    if trimmed.len() >= 16 {
    60→        trimmed[..16].to_string()
    61→    } else {
    62→        trimmed.to_string()
    63→    }
    64→}
    65→
    66→/// Parse commit format: jjb:HALLMARK:IDENTITY:ACTION: message
    67→/// Filters by firemark identity.
    68→pub fn zjjrs_parse_new_format(subject: &str, firemark_raw: &str) -> Option<jjrs_SteeplechaseEntry> {
    69→    // Expected format: jjb:HALLMARK:IDENTITY:ACTION: message
    70→    if !subject.starts_with("jjb:") {
    71→        return None;
    72→    }
    73→
    74→    // Skip past "jjb:" to get hallmark
    75→    let after_jjb = &subject[4..]; // skip "jjb:"
    76→
    77→    // Parse hallmark (required) - find next colon
    78→    let hallmark_end = after_jjb.find(':')?;
    79→    let hallmark_str = &after_jjb[..hallmark_end];
    80→    let hallmark = Some(hallmark_str.to_string());
    81→    let after_hallmark = &after_jjb[hallmark_end + 1..];
    82→
    83→    // Parse identity (₢CORONET or ₣FIREMARK)
    84→    let (identity, rest) = if after_hallmark.starts_with(CORONET_PREFIX) {
    85→        // Coronet: ₢XXXXX (1 prefix char + 5 base64 chars = 6 chars total in UTF-8)
    86→        let coronet_end = CORONET_PREFIX.len_utf8() + 5;
    87→        if after_hallmark.len() < coronet_end {
    88→            return None;
    89→        }
    90→        let coronet = &after_hallmark[..coronet_end];
    91→        // Verify this coronet belongs to our heat (first 2 chars of base64 match firemark)
    92→        let coronet_heat = &after_hallmark[CORONET_PREFIX.len_utf8()..CORONET_PREFIX.len_utf8() + 2];
    93→        if coronet_heat != firemark_raw {
    94→            return None;
    95→        }
    96→        (Some(coronet.to_string()), &after_hallmark[coronet_end..])
    97→    } else if after_hallmark.starts_with(FIREMARK_PREFIX) {
    98→        // Firemark: ₣XX (1 prefix char + 2 base64 chars)
    99→        let firemark_end = FIREMARK_PREFIX.len_utf8() + 2;
   100→        if after_hallmark.len() < firemark_end {
   101→            return None;
   102→        }
   103→        // Verify this is our firemark
   104→        let fm = &after_hallmark[FIREMARK_PREFIX.len_utf8()..firemark_end];
   105→        if fm != firemark_raw {
   106→            return None;
   107→        }
   108→        (None, &after_hallmark[firemark_end..])
   109→    } else {
   110→        return None;
   111→    };
   112→
   113→    // Now parse: [:ACTION]: message
   114→    // rest should start with either ": " (no action) or ":X: " (with action)
   115→    if !rest.starts_with(':') {
   116→        return None;
   117→    }
   118→
   119→    let after_colon = &rest[1..];
   120→
   121→    let (action, message) = if after_colon.starts_with(' ') {
   122→        // No action code, just ": message"
   123→        (None, after_colon[1..].to_string())
   124→    } else {
   125→        // Has action code: "X: message"
   126→        // Find the next colon
   127→        if let Some(colon_pos) = after_colon.find(':') {
   128→            let action_code = &after_colon[..colon_pos];
   129→            let msg = after_colon[colon_pos + 1..].trim_start().to_string();
   130→            (Some(action_code.to_string()), msg)
   131→        } else {
   132→            return None;
   133→        }
   134→    };
   135→
   136→    Some(jjrs_SteeplechaseEntry {
   137→        timestamp: String::new(), // filled by caller
   138→        commit: String::new(),    // filled by caller
   139→        hallmark,
   140→        coronet: identity,
   141→        action,
   142→        subject: message,
   143→    })
   144→}
   145→
   146→/// Parse a single git log line into a SteeplechaseEntry
   147→/// Line format: "YYYY-MM-DD HH:MM:SS -ZZZZ<TAB>abbrev_commit<TAB>subject"
   148→pub fn zjjrs_parse_log_line(line: &str, firemark_raw: &str) -> Option<jjrs_SteeplechaseEntry> {
   149→    let parts: Vec<&str> = line.splitn(3, '\t').collect();
   150→    if parts.len() != 3 {
   151→        return None;
   152→    }
   153→
   154→    let timestamp = zjjrs_parse_timestamp(parts[0]);
   155→    let commit = parts[1].to_string();
   156→    let subject = parts[2];
   157→
   158→    // Try parsing new format
   159→    if let Some(mut entry) = zjjrs_parse_new_format(subject, firemark_raw) {
   160→        entry.timestamp = timestamp;
   161→        entry.commit = commit;
   162→        return Some(entry);
   163→    }
   164→
   165→    None
   166→}
   167→
   168→/// Get steeplechase entries for a heat (library function)
   169→pub fn jjrs_get_entries(args: &jjrs_ReinArgs) -> Result<Vec<jjrs_SteeplechaseEntry>, String> {
   170→    let firemark = Firemark::jjrf_parse(&args.firemark)
   171→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   172→
   173→    let firemark_raw = firemark.jjrf_as_str();
   174→
   175→    // Build the grep pattern for git log
   176→    // Format: jjb:HALLMARK:IDENTITY:ACTION: message
   177→    // Pattern matches both heat-level (₣XX) and pace-level (₢XX...) entries
   178→    let grep_pattern = format!(
   179→        "^jjb:[^:]+:({}{}|{}{})",
   180→        FIREMARK_PREFIX, firemark_raw,
   181→        CORONET_PREFIX, firemark_raw
   182→    );
   183→
   184→    let output = Command::new("git")
   185→        .args([
   186→            "log",
   187→            "--all",
   188→            "--extended-regexp",
   189→            &format!("--grep={}", grep_pattern),
   190→            "--format=%ai\t%h\t%s",
   191→        ])
   192→        .output()
   193→        .map_err(|e| format!("Failed to run git log: {}", e))?;
   194→
   195→    if !output.status.success() {
   196→        let stderr = String::from_utf8_lossy(&output.stderr);
   197→        return Err(format!("git log failed: {}", stderr));
   198→    }
   199→
   200→    let stdout = String::from_utf8_lossy(&output.stdout);
   201→
   202→    let entries: Vec<jjrs_SteeplechaseEntry> = stdout
   203→        .lines()
   204→        .filter_map(|line| zjjrs_parse_log_line(line, firemark_raw))
   205→        .take(args.limit)
   206→        .collect();
   207→
   208→    Ok(entries)
   209→}
   210→
   211→/// Run jjx_rein command (CLI wrapper)
   212→pub fn jjrs_run(args: jjrs_ReinArgs) -> i32 {
   213→    match jjrs_get_entries(&args) {
   214→        Ok(entries) => {
   215→            match serde_json::to_string_pretty(&entries) {
   216→                Ok(json) => {
   217→                    println!("{}", json);
   218→                    0
   219→                }
   220→                Err(e) => {
   221→                    eprintln!("rein: error: failed to serialize JSON: {}", e);
   222→                    1
   223→                }
   224→            }
   225→        }
   226→        Err(e) => {
   227→            eprintln!("rein: error: {}", e);
   228→            1
   229→        }
   230→    }
   231→}
   232→

