pub fn jjrs_run(args: jjrs_ReinArgs) -> i32 {
    match jjrs_get_entries(&args) {
        Ok(entries) => {
            match serde_json::to_string_pretty(&entries) {
                Ok(json) => {
                    println!("{}", json);
                    0
